import{_ as t,o as a,c as r,a3 as o}from"./chunks/framework.BveOjhN0.js";const p=JSON.parse('{"title":"Platform Release — v1.1.0-platform","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Platform Release — v1.1.0-platform | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/changelog/v1.1.0-platform"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Platform Release — v1.1.0-platform | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/changelog/v1.1.0-platform"}]]},"headers":[],"relativePath":"changelog/v1.1.0-platform.md","filePath":"changelog/v1.1.0-platform.md","lastUpdated":1784076469000}'),n={name:"changelog/v1.1.0-platform.md"};function i(s,e,d,l,c,m){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="platform-release-—-v1-1-0-platform" tabindex="-1">Platform Release — v1.1.0-platform <a class="header-anchor" href="#platform-release-—-v1-1-0-platform" aria-label="Permalink to &quot;Platform Release — v1.1.0-platform&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td><strong>Release tag</strong></td><td><code>v1.1.0-platform</code></td></tr><tr><td><strong>Release date</strong></td><td>2026-07-13</td></tr><tr><td><strong>Platform status</strong></td><td><strong>Frozen / Production Ready</strong></td></tr><tr><td><strong>Scope</strong></td><td>SaaS Platform Foundation (Central + Tenant). No new CRM/ERP business modules beyond Leads &amp; Tasks reference modules.</td></tr></tbody></table><p>This document is the official <strong>Platform Foundation</strong> release record. All subsequent product work belongs to business modules (CRM Sprint 2+, Sales, Billing modules, ERP, etc.), not platform redesign.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>SaleOS v1.1.0 freezes the shared multi-tenant foundation:</p><ul><li><strong>Backend:</strong> Laravel 13, Sanctum, Spatie Permission, Cashier (Stripe)</li><li><strong>Frontend:</strong> React 19 SPA (Central admin + Tenant application) with shared AppLayout</li><li><strong>Docs:</strong> Architecture, auth, billing, settings, RBAC, module standard, testing guides</li></ul><p>Verified green: Pest <strong>230/230</strong>, Playwright <strong>69/69</strong>, manual browser QA — production-ready.</p><hr><h2 id="architecture-summary" tabindex="-1">Architecture Summary <a class="header-anchor" href="#architecture-summary" aria-label="Permalink to &quot;Architecture Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Responsibility</th></tr></thead><tbody><tr><td>Authentication</td><td>Central + Tenant login/register, email verification, password reset, remember-me, lockout</td></tr><tr><td>Tenancy</td><td>Workspace isolation, domains, provisioning, entitlements</td></tr><tr><td>Authorization</td><td>Module licensing (<code>module:{slug}</code>) + Spatie RBAC (<code>can:{permission}</code>)</td></tr><tr><td>Marketplace</td><td>Module catalog, install/cancel/deactivate, default-included Leads/Tasks</td></tr><tr><td>Billing</td><td>Gateway-agnostic invoices/payments, consolidated billing, Stripe + Manual drivers</td></tr><tr><td>Settings</td><td>Central → Tenant → system hierarchy (branding, mail, locale, currency)</td></tr><tr><td>Security</td><td>Audit logs, impersonation sessions, suspended users, lockout</td></tr><tr><td>Reference modules</td><td><strong>Leads</strong>, <strong>Tasks</strong> (blueprint for all future modules)</td></tr></tbody></table><p>See <a href="/getting-started/platform-freeze">architecture/platform-freeze.md</a>.</p><hr><h2 id="completed-features" tabindex="-1">Completed Features <a class="header-anchor" href="#completed-features" aria-label="Permalink to &quot;Completed Features&quot;">​</a></h2><h3 id="central-application" tabindex="-1">Central Application <a class="header-anchor" href="#central-application" aria-label="Permalink to &quot;Central Application&quot;">​</a></h3><p>Dashboard, Tenants, Users, Roles &amp; permissions, Modules, Marketplace, Billing (invoices/payments), Payment gateways, System settings, Profile, Impersonation, Logout.</p><h3 id="tenant-application" tabindex="-1">Tenant Application <a class="header-anchor" href="#tenant-application" aria-label="Permalink to &quot;Tenant Application&quot;">​</a></h3><p>Registration + email verification, Login (workspace-aware), Dashboard, <strong>Leads</strong>, <strong>Tasks</strong>, Users &amp; roles, Workspace settings, Profile, Logout.</p><h3 id="cross-cutting" tabindex="-1">Cross-cutting <a class="header-anchor" href="#cross-cutting" aria-label="Permalink to &quot;Cross-cutting&quot;">​</a></h3><p>Shared AppLayout, localization, branding assets, platform audit + Spatie activity logging, Playwright E2E, Pest feature coverage.</p><hr><h2 id="database-changes" tabindex="-1">Database Changes <a class="header-anchor" href="#database-changes" aria-label="Permalink to &quot;Database Changes&quot;">​</a></h2><p>Identity, RBAC, module catalog/subscriptions, billing ledger, payment gateways, settings, activity/impersonation, Leads, and Tasks tables as documented in <a href="/developer-guide/database">architecture/database.md</a>.</p><p><strong>v1.1.0 hardening:</strong> billing webhook tenant resolution via <code>payment_id</code> metadata fallback; auth lockout messaging; expanded validation/security tests. No greenfield schema redesign.</p><hr><h2 id="breaking-changes" tabindex="-1">Breaking Changes <a class="header-anchor" href="#breaking-changes" aria-label="Permalink to &quot;Breaking Changes&quot;">​</a></h2><p>Relative to the pre-marketplace / plan-based licensing era:</p><ol><li>Plans / Features / usage limits removed — licensing is module subscriptions only.</li><li>Central SPA routes under <code>/central/*</code>.</li><li>Entitlements API shape <code>{ core, modules }</code>.</li></ol><p>Within the modular-marketplace line, v1.1.0 is a hardening release (no additional intended API breaks).</p><hr><h2 id="permissions-added" tabindex="-1">Permissions Added <a class="header-anchor" href="#permissions-added" aria-label="Permalink to &quot;Permissions Added&quot;">​</a></h2><p><strong>Central:</strong> <code>users.*</code>, <code>tenants.*</code>, <code>roles.*</code>, <code>dashboard.view</code>, <code>billing.manage</code>, <code>payment-gateways.*</code>, <code>modules.*</code>, <code>module-subscriptions.*</code>, <code>system-settings.*</code>, <code>invoices.*</code>, <code>payments.*</code>, <code>impersonation.*</code>.</p><p><strong>Tenant:</strong> <code>dashboard.view</code>, <code>users.*</code>, <code>roles.*</code>, <code>settings.*</code>, <code>leads.view|create|update|delete|assign</code>, <code>tasks.view|create|update|delete|assign|complete</code>.</p><hr><h2 id="routes-added" tabindex="-1">Routes Added <a class="header-anchor" href="#routes-added" aria-label="Permalink to &quot;Routes Added&quot;">​</a></h2><p>~133 application API routes under <code>/api/central/v1/*</code> and <code>/api/tenant/v1/*</code> (auth, tenants, users, roles, modules, marketplace, billing, gateways, settings, leads, tasks). See API docs under <code>api/</code>.</p><hr><h2 id="api-changes-v1-1-0-hardening" tabindex="-1">API Changes (v1.1.0 hardening) <a class="header-anchor" href="#api-changes-v1-1-0-hardening" aria-label="Permalink to &quot;API Changes (v1.1.0 hardening)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Change</th><th>Detail</th></tr></thead><tbody><tr><td>Login lockout</td><td>Message includes minutes remaining (Central + Tenant)</td></tr><tr><td>Billing webhook resolve</td><td>Fallback <code>meta.payment_id</code> → <code>payments</code></td></tr><tr><td>Verify-email gate</td><td>Sign out navigates to context login</td></tr><tr><td>Tenant public settings</td><td>Resolve correctly with auth on localhost</td></tr></tbody></table><hr><h2 id="testing-summary" tabindex="-1">Testing Summary <a class="header-anchor" href="#testing-summary" aria-label="Permalink to &quot;Testing Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gate</th><th>Result</th></tr></thead><tbody><tr><td>Pest</td><td><strong>230 / 230</strong></td></tr><tr><td>Playwright (all projects)</td><td><strong>69 / 69</strong></td></tr><tr><td>Frontend lint / tsc / build</td><td>Pass</td></tr><tr><td>Manual browser QA</td><td>Central + Tenant happy paths pass</td></tr></tbody></table><hr><h2 id="security-improvements" tabindex="-1">Security Improvements <a class="header-anchor" href="#security-improvements" aria-label="Permalink to &quot;Security Improvements&quot;">​</a></h2><p>Lockout messaging, email verification gate, remember-me/token expiration coverage, workspace availability login checks, module gate after deactivate, audited impersonation, webhook failure coverage.</p><hr><h2 id="performance-improvements" tabindex="-1">Performance Improvements <a class="header-anchor" href="#performance-improvements" aria-label="Permalink to &quot;Performance Improvements&quot;">​</a></h2><p>Namespaced tenant setting caches, stabilized dashboard series for QA, Playwright workers=1 locally for deterministic auth/settings flows.</p><hr><h2 id="known-limitations" tabindex="-1">Known Limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to &quot;Known Limitations&quot;">​</a></h2><ul><li>Logout-all-devices not implemented</li><li>Invoice/payment write UI limited (read ledger + engine; some Central Billing screens are placeholders)</li><li>Creem refunds are dashboard-operated (not via API)</li><li>Contacts / Companies / Calendar / Activities planned for CRM Sprint 2+</li><li>Lead convert is status-only until Contacts module ships</li></ul><hr><h2 id="upgrade-notes" tabindex="-1">Upgrade Notes <a class="header-anchor" href="#upgrade-notes" aria-label="Permalink to &quot;Upgrade Notes&quot;">​</a></h2><ol><li>Deploy Backend, Frontend, Docs from tag <code>v1.1.0-platform</code> (or merged <code>main</code> at that tag).</li><li>Run migrations + required seeders; configure Sanctum, mail, Stripe, SPA URLs.</li><li>Verify <code>/central/login</code> and tenant register/login.</li><li>Re-run Pest + Playwright in staging before promote.</li><li>Branch CRM work from a new feature branch — do not continue platform redesign on this freeze.</li></ol><hr><h2 id="future-roadmap" tabindex="-1">Future Roadmap <a class="header-anchor" href="#future-roadmap" aria-label="Permalink to &quot;Future Roadmap&quot;">​</a></h2><p>CRM Sprint 2 (Contacts, Companies, Calendar, Activities) → Sales → Billing modules → ERP. See <a href="/getting-started/product-roadmap">product-roadmap.md</a>.</p><hr><h2 id="release-date" tabindex="-1">Release Date <a class="header-anchor" href="#release-date" aria-label="Permalink to &quot;Release Date&quot;">​</a></h2><p><strong>2026-07-13</strong></p><h2 id="platform-status" tabindex="-1">Platform Status <a class="header-anchor" href="#platform-status" aria-label="Permalink to &quot;Platform Status&quot;">​</a></h2><p><strong>OFFICIALLY FROZEN — Production Ready</strong></p><p>Tag: <strong><code>v1.1.0-platform</code></strong></p><h3 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h3><ul><li><a href="/changelog/">CHANGELOG</a></li><li><a href="/getting-started/product-roadmap">Product roadmap</a></li><li><a href="/getting-started/platform-freeze">Platform freeze</a></li><li><a href="/developer-guide/module-development">Module development</a></li></ul>',65)])])}const u=t(n,[["render",i]]);export{p as __pageData,u as default};
